let x = 100;
let y = 200;
let diameter = 50;
let kleurR = 255;
let kleurG = 0;
let kleurB = 0;

function setup() {
  createCanvas(600, 400);
}

function draw() {
  background(245);

  fill(kleurR, kleurG, kleurB);
  ellipse(x, y, diameter, diameter);

  // Beweeg naar rechts
  x += 1;

  // Als buiten scherm, begin opnieuw
  if (x > width) {
    x = 0;
  }
}

